   228	// TestUpdateInstallTriggers_DoesNotCorruptOtherScope is the core regression test for
   229	// the reported escalation: creating an agency postback must not flip the advertiser
   230	// trigger's filter_agency_network, which would hide it from the advertiser (FetchTriggers
   231	// filters filter_agency_network=0) and make the postback show as Active.
   232	func TestUpdateInstallTriggers_DoesNotCorruptOtherScope(t *testing.T) {
   233		globalDB, cleanup := setupTriggersTestDB(t)
   234		defer cleanup()
   235	
   236		// Add an agency-level trigger alongside the advertiser trigger (id=2, agency=0).
   237		err := globalDB.InsertInstallTriggers(100, 1000, 2, 777)
   238		require.NoError(t, err)
   239	
   240		// Simulate the agency create path updating its own scope.
   241		err = globalDB.UpdateInstallTriggers(100, 1000, 2, 777)
   242		require.NoError(t, err)
   243	
   244		// The advertiser trigger must be untouched: still agency=0, still visible.
   245		advTriggers, err := globalDB.GetPostbackTriggers(map[string]any{"id": 2}, "")
   246		require.NoError(t, err)
   247		require.Len(t, advTriggers, 1)
   248		assert.Equal(t, 0, advTriggers[0].FilterAgencyNetwork,
   249			"advertiser trigger filter_agency_network must remain 0 after an agency update")
   250	
   251		// And it remains discoverable via the advertiser-scoped FetchTriggers path.
   252		visible, err := globalDB.FetchTriggers(context.Background(), "1000", nil)
   253		require.NoError(t, err)
   254		found := false
   255		for _, tr := range visible {
   256			if tr.ID == 2 {
   257				found = true
   258			}
   259		}
   260		assert.True(t, found, "advertiser trigger must remain visible to FetchTriggers (filter_agency_network=0)")
   261	}
